import{_ as a,o as t,c as o,a7 as i}from"./chunks/framework.BPD8m7Vq.js";const k=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"PaiSmart/面试/v2-day5.md","filePath":"PaiSmart/面试/v2-day5.md","lastUpdated":1774448547000}'),l={name:"PaiSmart/面试/v2-day5.md"};function s(r,e,d,c,n,u){return t(),o("div",null,[...e[0]||(e[0]=[i('<h3 id="websocket" tabindex="-1">WebSocket <a class="header-anchor" href="#websocket" aria-label="Permalink to &quot;WebSocket&quot;">​</a></h3><ul><li>用户建立 WebSocket 连接后，系统会根据路径中的 JWT 提取当前用户的 username，从而识别当前是哪位用户在发起对话。收到消息后，后端会根据 userId 获取或创建当前会话的 conversationId，这个 conversationId 用来标识当前这段连续会话，而不是每条消息都新建一个。然后系统会从 Redis 中读取该 conversationId 对应的历史消息，作为多轮对话的上下文基础。接着，系统会基于用户当前输入的消息和 userId 做带权限的检索，拿到检索结果后，通过 <code>buildContext</code> 组装成 context。最后再把 userMessage、history 和 context 一起交给 DeepSeek。DeepSeek 会以流式方式返回 chunk，后端再通过 WebSocket 将这些 chunk 持续推送给前端，所以前端会呈现出流式输出的效果。等本轮回答完成后，后端会发送 completion 通知，并将这次用户消息和模型回复写回 Redis。为了避免历史过长，系统只保留最近 20 条消息。</li></ul><h3 id="websocket-对比于-http-的优势" tabindex="-1">WebSocket 对比于 HTTP 的优势 <a class="header-anchor" href="#websocket-对比于-http-的优势" aria-label="Permalink to &quot;WebSocket 对比于 HTTP 的优势&quot;">​</a></h3><ul><li>WebSocket具备全双工的协议，不像HTTP一样只可以一方发送消息一方被动接受消息。也正是因为WebSocket可以实时支持服务端主动给用户端推送数据发送消息，因此选择WebSocket来实现这个流式打印。</li></ul><h3 id="websocket-如果因为网络抖动而连接断了。。。" tabindex="-1">WebSocket 如果因为网络抖动而连接断了。。。 <a class="header-anchor" href="#websocket-如果因为网络抖动而连接断了。。。" aria-label="Permalink to &quot;WebSocket 如果因为网络抖动而连接断了。。。&quot;">​</a></h3><ul><li>在前端增加了重连机制，在后端增加了会话恢复能力。</li><li>前端这边，我们使用了 @vueuse 库来管理 WebSocket 连接，它内置了强大的心跳重连机制。一旦连接意外断开，它就会自动尝试重连。而且这个重连不是死磕式的，也就是说每次失败后等待时间都会变长，避免高频的重试对服务器造成压力。除此之外，它还支持心跳机制，会定期发送 ping 消息检测连接是否健康，如果发现连接已经“僵死”，也能主动触发重连。</li><li>后端这边我们遵循的是“无状态连接”原则。比如用户重连后重新发一条消息，我们通过 userId 定位当前 conversationId 恢复上下文，然后接着处理，就好像这条连接从来没断过一样。</li></ul><h3 id="为什么使用redis而不使用mysql" tabindex="-1">为什么使用Redis而不使用Mysql <a class="header-anchor" href="#为什么使用redis而不使用mysql" aria-label="Permalink to &quot;为什么使用Redis而不使用Mysql&quot;">​</a></h3><ul><li>一是这是一个高频读写的任务，虽然Mysql很快，但是Redis比Mysql还快好几个数量级，非常适合这种实时性要求比较高的业务</li><li>二是因为我们需要的上下文不多，不需要持久化，存放在Redis中只需要设置一个TTL就可以自动清除，如果存放在Mysql中，还需要设置一个定时任务来清除</li></ul><h3 id="在redis中如何设计数据结构-例如如何找到一个用户的对话历史" tabindex="-1">在Redis中如何设计数据结构，例如如何找到一个用户的对话历史 <a class="header-anchor" href="#在redis中如何设计数据结构-例如如何找到一个用户的对话历史" aria-label="Permalink to &quot;在Redis中如何设计数据结构，例如如何找到一个用户的对话历史&quot;">​</a></h3><ul><li>设置了两种key</li><li>第一种 key 用于定位用户的会话，格式为 <code>user:{userId}:current_conversation</code>，value 是一个 UUID 的字符串。</li><li>第二种 key 用于存储真正的聊天记录，它的格式是：<code>conversation:{conversationId}</code>，value 是一个 JSON 字符串，该字符串序列化了一个包含多条对话的列表。</li></ul><h3 id="多轮对话如何管理和利用上下文" tabindex="-1">多轮对话如何管理和利用上下文？ <a class="header-anchor" href="#多轮对话如何管理和利用上下文" aria-label="Permalink to &quot;多轮对话如何管理和利用上下文？&quot;">​</a></h3><ul><li>当前采用了基于Redis的对话历史管理机制，每个用户有一个唯一的ID，所有对话都按时间顺序存放在Redis中，设置了7天的过期时间</li></ul>',12)])])}const b=a(l,[["render",s]]);export{k as __pageData,b as default};
